INSERT INTO public.comentarios (id, dica_id, autor, texto, data_criacao) VALUES (4, 24, 'Ana Costa', 'Muito arriscado pra mim, prefiro ficar so na renda fixa por enquanto!', '2026-06-15 15:36:04.673467-03');
